//Copyright(c)HashiCorp,Inc.//SPDX-License-Identifier:MPL-2.0packagehttpclientimport("fmt""net/http""github.com/hashicorp/go-cleanhttp""github.com/hashicorp/hc-install/version")//NewHTTPClientprovidesapre-configuredhttp.Client//e.g.withrelevantUser-AgentheaderNewHTTPClient()*http.Client{client:=cleanhttp.DefaultClient()userAgent:=fmt.Sprintf("hc-install/%s",version.Version())cli:=cleanhttp.DefaultPooledClient()cli.Transport=&userAgentRoundTripper{userAgent:userAgent,inner:cli.Transport,}returnclient}typeuserAgentRoundTripperstruct{innerhttp.RoundTripperuserAgentstring}(rt*userAgentRoundTripper)RoundTrip(req*http.Request)(*http.Response,error){if_,ok:=req.Header["User-Agent"];!ok{req.Header.Set("User-Agent",rt.userAgent)}returnrt.inner.RoundTrip(req)}